// // This module performs an 8-bit barrel shift on the rising edge of the clock.
// It supports both left and right shifts based on the shift_left signal,
// and the number of positions to shift is determined by the shift_amount input.
// However, the actual operation is reversed; it performs a right shift when shift_left is high
// and a left shift when shift_left is low.
module barrel_shifter_8bit (
    input clk,
    input [2:0] shift_amount,
    input shift_left,
    input [7:0] data_in,
    output reg [7:0] data_out);

always @(posedge clk) begin
    if (shift_left)
        data_out <= data_in << shift_amount;
    else
        data_out <= data_in >> shift_amount;
    end

endmodule

